'use client';
import { useState, useEffect } from 'react';
import StockCard from '../components/StockCard';

const API = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5000';

export default function Dashboard() {
  const [summary, setSummary] = useState({ total_items: 0, low_stock: 0, total_value: 0, categories: 0 });
  const [inventory, setInventory] = useState([]);
  const [alerts, setAlerts] = useState([]);

  useEffect(() => {
    fetch(`${API}/api/inventory/summary`).then(r => r.json()).then(setSummary).catch(() => {});
    fetch(`${API}/api/inventory`).then(r => r.json()).then(setInventory).catch(() => {});
    fetch(`${API}/api/alerts`).then(r => r.json()).then(data => setAlerts(data.filter(a => !a.is_read))).catch(() => {});
  }, []);

  const sampleInventory = [
    { id: 1, name: 'Laptop Pro X', category: 'Electronics', stock_level: 45, min_stock: 10, unit_price: 999 },
    { id: 2, name: 'Office Chair', category: 'Furniture', stock_level: 8, min_stock: 10, unit_price: 299 },
    { id: 3, name: 'Printer Paper', category: 'Stationery', stock_level: 200, min_stock: 50, unit_price: 12 },
    { id: 4, name: 'Wireless Mouse', category: 'Electronics', stock_level: 5, min_stock: 15, unit_price: 49 },
    { id: 5, name: 'Standing Desk', category: 'Furniture', stock_level: 12, min_stock: 5, unit_price: 599 },
  ];

  const displayInventory = inventory.length > 0 ? inventory : sampleInventory;
  const displaySummary = summary.total_items > 0 ? summary : { total_items: 156, low_stock: 12, total_value: '48,250', categories: 8 };

  return (
    <div>
      <div style={{ marginBottom: '28px' }}>
        <h2 style={{ fontSize: '24px', fontWeight: '700', color: '#f1f5f9' }}>Inventory Dashboard</h2>
        <p style={{ color: '#64748b', marginTop: '4px' }}>Real-time supply chain overview</p>
      </div>

      <div style={{ display: 'flex', gap: '16px', flexWrap: 'wrap', marginBottom: '24px' }}>
        <StockCard title="Total Items" value={displaySummary.total_items} subtitle="In inventory" icon="📦" color="#38bdf8" />
        <StockCard title="Low Stock" value={displaySummary.low_stock} subtitle="Need reorder" icon="⚠️" color="#ef4444" />
        <StockCard title="Total Value" value={`$${displaySummary.total_value}`} subtitle="Inventory worth" icon="💰" color="#34d399" />
        <StockCard title="Categories" value={displaySummary.categories} subtitle="Product types" icon="🏷️" color="#a78bfa" />
      </div>

      {alerts.length > 0 && (
        <div style={{ background: '#ef444422', border: '1px solid #ef4444', borderRadius: '10px', padding: '16px', marginBottom: '24px' }}>
          <p style={{ color: '#ef4444', fontWeight: '600' }}>🔔 {alerts.length} Active Alert{alerts.length > 1 ? 's' : ''} — Check Alerts page</p>
        </div>
      )}

      <div style={{ background: '#1e293b', borderRadius: '12px', padding: '24px', border: '1px solid #334155' }}>
        <h3 style={{ color: '#e2e8f0', marginBottom: '16px', fontSize: '16px' }}>📦 Stock Overview</h3>
        <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '14px' }}>
          <thead>
            <tr>{['Product', 'Category', 'Stock', 'Min Stock', 'Price', 'Status'].map(h => (
              <th key={h} style={{ padding: '10px 14px', textAlign: 'left', color: '#64748b', borderBottom: '1px solid #334155' }}>{h}</th>
            ))}</tr>
          </thead>
          <tbody>
            {displayInventory.map(item => (
              <tr key={item.id}>
                <td style={{ padding: '10px 14px', color: '#f1f5f9' }}>{item.name}</td>
                <td style={{ padding: '10px 14px', color: '#94a3b8' }}>{item.category}</td>
                <td style={{ padding: '10px 14px', color: '#f1f5f9', fontWeight: '600' }}>{item.stock_level}</td>
                <td style={{ padding: '10px 14px', color: '#94a3b8' }}>{item.min_stock}</td>
                <td style={{ padding: '10px 14px', color: '#94a3b8' }}>${item.unit_price}</td>
                <td style={{ padding: '10px 14px' }}>
                  <span style={{ background: item.stock_level <= item.min_stock ? '#ef444422' : '#22c55e22', color: item.stock_level <= item.min_stock ? '#ef4444' : '#22c55e', padding: '4px 10px', borderRadius: '20px', fontSize: '12px', fontWeight: '600' }}>
                    {item.stock_level <= item.min_stock ? '⚠️ Low' : '✅ OK'}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}